            if dp[i] != float('inf'):
                j = i + math.ceil(softness / (2 ** dp[i]))
                if j <= C:
                    new_dp[j] = min(new_dp[j], dp[i] + 1)
        dp = new_dp

    return "YES" if dp[C] != float('inf') else "NO"

