import sys
import math

def can_reach_softness(N, C, softness_values):
    max_softness = max(softness_values)
    if max_softness >= C:
        return True

    softness_values = sorted(softness_values, reverse=True)
    memo = {}

    def dfs(current_softness, depth):
        if (current_softness, depth) in memo:
            return memo[(current_softness, depth)]
        if current_softness == C:
            return True
        if current_softness > C or depth >= N:
            return False

        result = False
        for i, softness in enumerate(softness_values):
            next_softness = current_softness + math.ceil(softness / (2 ** depth))
            if next_softness <= C:
                result = result or dfs(next_softness, depth + 1)
        memo[(current_softness, depth)] = result
        return result

    return dfs(0, 0)

def main():
